+        );
+        let methods = reflection.method_names();
+        crate::assert_with_log!(
+            methods.contains(&"ServerReflectionInfo"),
+            "method names includes reflection entrypoint",
+            true,
+            methods.contains(&"ServerReflectionInfo")
+        );
+        crate::test_complete!("reflection_service_traits");
+    }
+}

